// Handle errors gracefully
map.on('error', (e) => {
  console.warn('Map error:', e.error?.message || e);
});

// UI Controls
const pitchSlider = document.getElementById('pitch');
const pitchValue = document.getElementById('pitch-value');
const zoomSlider = document.getElementById('zoom');
const zoomValue = document.getElementById('zoom-value');

pitchSlider.addEventListener('input', (e) => {
  const pitch = parseInt(e.target.value);
  pitchValue.textContent = pitch;
  map.setPitch(pitch);
});

zoomSlider.addEventListener('input', (e) => {
  const zoom = parseFloat(e.target.value);
  zoomValue.textContent = zoom.toFixed(1);
  map.setZoom(zoom);
});

// Update sliders on map move
map.on('move', () => {
  pitchSlider.value = map.getPitch();
  pitchValue.textContent = Math.round(map.getPitch());
  zoomSlider.value = map.getZoom();
  zoomValue.textContent = map.getZoom().toFixed(1);
});

// Keyboard shortcuts
document.addEventListener('keydown', (e) => {
  if (e.key === 'r') {
    // Reset view
    map.flyTo({
      center: LISBON_CENTER,
      zoom: 15,
      pitch: 60,
      bearing: -20,
      duration: 1500
    });
  } else if (e.key === 't') {
    // Toggle terrain (if available)
    const terrain = map.getTerrain();
    if (terrain) {
      map.setTerrain(null);
      console.log('⛰️ Terrain disabled');
    } else if (map.getSource('terrain')) {
      map.setTerrain({ source: 'terrain', exaggeration: 1.5 });
      console.log('⛰️ Terrain enabled');
    }
  }
});

console.log('🗺️ Lisbon 3D Explorer initializing...');
console.log('   Press R to reset view, T to toggle terrain');
